import React, { useState } from 'react';
import { Link } from 'gatsby';
import Header from '../components/header/header';
import Footer from '../components/Footer/Footer';
import { useCMS } from '../contexts/CMSContext';
import { ResolvedContentProvider } from '../ppm/util/ResolvedContentContext';
import '../components/news/new.css';
import '../global.css';

// Local helper component for news list items to ensure consistency with homepage
const AnnouncementContent: React.FC<{ item: any }> = ({ item }) => (
  <>
    <div className="announcement-thumb">
      {item.image ? (
        <img
          src={item.image}
          alt={item.title}
          className="thumb-img"
          onError={(e) => {
            e.currentTarget.style.display = 'none';
            const parent = e.currentTarget.parentElement;
            if (parent) {
              parent.classList.add('no-image');
            }
          }}
        />
      ) : null}
      <div className="thumb-fallback">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1">
          <path d="M4 12V4a2 2 0 0 1 2-2h12a2 2 0 0 1 2 2v16a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2v-4" />
          <polyline points="10 9 15 12 10 15" />
        </svg>
      </div>
    </div>

    <div className="announcement-text">
      <h4 className="announcement-title">{item.title}</h4>
      <p className="announcement-description">{item.cleanSubtitle}</p>
    </div>
  </>
);

const NewsPageInner = () => {
  const { displayData } = useCMS();
  const newsData = displayData.pages.newsPage;
  const supportContent = displayData.pages.home.supportContent;
  
  const [visibleCount, setVisibleCount] = useState(12);
  const [searchQuery, setSearchQuery] = useState('');

  // Handle hash navigation
  React.useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash) {
        const mapping: {[key:string]: string} = {
          '#phat-su': 'Phật sự',
          '#thong-cao': 'Thông cáo'
        };
        const searchVal = mapping[hash.toLowerCase()];
        if (searchVal) {
          setSearchQuery(searchVal);
          // Scroll to grid
          const grid = document.querySelector('.announcements-items');
          if (grid) grid.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
      }
    };
    handleHash();
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, []);

  // SBU TV Data for the left block
  const tvSection = supportContent?.columns.find((c: any) => c.id === 'tv');
  const tvLink = tvSection?.items?.[0]?.link || '/videos';
  const tvTitle = tvSection?.title || 'BỒ ĐỀ PHẬT QUỐC TV 57.15';

  // Extract first image
  const extractFirstImage = (body: string | undefined) => {
    if (!body) return null;
    const imgMatch = body.match(/src=["']([^"']+\.(?:jpg|jpeg|png|gif|webp|bmp))["']/i);
    let imageUrl = imgMatch ? imgMatch[1] : null;

    if (imageUrl) {
      imageUrl = imageUrl.replace(
        /http:\/\/bodephatquoc\.org\/wp-content\/uploads\//g, 
        'https://ik.imagekit.io/dloitl7fd8/wp-content/uploads/'
      );
    }
    return imageUrl;
  };

  // Helper to strip HTML tags
  const stripHtml = (html: string | undefined) => {
    if (!html) return '';
    return html.replace(/<[^>]*>?/gm, '').replace(/&nbsp;/g, ' ').trim();
  };

  // Combine news items
  const allNews = [...(newsData.items || [])].map(item => ({
    ...item,
    image: item.image || extractFirstImage(item.body),
    cleanSubtitle: item.subtitle || stripHtml(item.body || '').substring(0, 200)
  })).sort((a, b) => {
    const dateA = a.date ? a.date.split('/').reverse().join('-') : '';
    const dateB = b.date ? b.date.split('/').reverse().join('-') : '';
    return dateB.localeCompare(dateA);
  });

  const filteredNews = allNews.filter(item => {
    if (!searchQuery) return true;
    const q = searchQuery.toLowerCase();
    return (
      (item.title || '').toLowerCase().includes(q) || 
      (item.subtitle || '').toLowerCase().includes(q) ||
      (item.cleanSubtitle || '').toLowerCase().includes(q)
    );
  });

  const displayedNews = filteredNews.slice(0, visibleCount);

  return (
    <div className="news-page-wrapper">
      <Header />
      <div style={{ height: '80px' }} />
      
      <section className="announcements-section">
        <div className="announcements-container">
          <div className="announcements-grid">
            {/* Left column - SBU TV Section */}
            <div className="announcements-featured">
              <div className="sticky-sidebar">
                <Link to={tvLink} className="featured-link-wrapper">
                  <div className="featured-image">
                    {tvSection?.items?.[0]?.videoId ? (
                      <img 
                        src={`https://img.youtube.com/vi/${tvSection.items[0].videoId}/hqdefault.jpg`} 
                        alt={tvTitle}
                        className="featured-img"
                      />
                    ) : (
                      <div className="image-placeholder">
                        <div className="placeholder-content">
                          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1">
                            <rect x="3" y="3" width="18" height="18" rx="2" ry="2"></rect>
                            <circle cx="8.5" cy="8.5" r="1.5"></circle>
                            <polyline points="21 15 16 10 5 21"></polyline>
                          </svg>
                          <span>SBU TV - 57.15</span>
                        </div>
                      </div>
                    )}
                  </div>
                  <div className="featured-content" style={{ marginTop: '1.5rem' }}>
                    <h3 className="featured-title">{tvTitle}</h3>
                    <p className="featured-subtitle">Kênh phát trực tiếp chương trình giáo dục và hoằng pháp của Bồ Đề Phật Quốc.</p>
                  </div>
                </Link>
              </div>
            </div>

            {/* Right column - Main News List */}
            <div className="announcements-list">
              <div className="list-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', flexWrap: 'wrap', gap: '2rem', marginBottom: '3rem' }}>
                <div>
                  <h2 className="section-title">{newsData.sectionTitle || 'Tất Cả Bản Tin'}</h2>
                  <div className="title-underline"></div>
                </div>
                
                <div className="search-box-container" style={{ flex: '1', maxWidth: '300px' }}>
                  <input 
                    type="text" 
                    placeholder="Tìm kiếm..." 
                    value={searchQuery}
                    onChange={(e) => {
                      setSearchQuery(e.target.value);
                      setVisibleCount(12);
                    }}
                    style={{
                      width: '100%',
                      padding: '10px 20px',
                      borderRadius: '25px',
                      border: '1px solid var(--color-border)',
                      fontSize: '0.9rem',
                      outline: 'none',
                      fontFamily: 'var(--font-sans)',
                      backgroundColor: 'white'
                    }}
                  />
                </div>
              </div>

              <div className="announcements-items">
                {displayedNews.map((item: any, idx) => {
                  const isExternal = item.link?.startsWith('http');
                  return (
                    <div className="announcement-item" key={`${item.id}-${idx}`}>
                      {isExternal ? (
                        <a href={item.link} className="announcement-item-link">
                          <AnnouncementContent item={item} />
                        </a>
                      ) : (
                        <Link to={item.link || '#'} className="announcement-item-link">
                          <AnnouncementContent item={item} />
                        </Link>
                      )}
                    </div>
                  );
                })}
              </div>

              {visibleCount < filteredNews.length && (
                <div style={{ display: 'flex', justifyContent: 'center', marginTop: '4rem' }}>
                  <button 
                    onClick={() => setVisibleCount(prev => prev + 12)}
                    className="view-all-link"
                    style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: '1.1rem' }}
                  >
                    Xem thêm bản tin
                    <svg className="view-all-arrow" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                      <path d="M5 12h14M12 5l7 7-7 7" />
                    </svg>
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      </section>
      
      <Footer />

      <style dangerouslySetInnerHTML={{ __html: `
        .news-page-wrapper {
          background-color: var(--color-off-white);
          min-height: 100vh;
        }
        .sticky-sidebar {
          position: sticky;
          top: 120px;
        }
        @media (max-width: 768px) {
          .announcements-grid {
            grid-template-columns: 1fr;
          }
          .announcements-featured {
            display: none !important;
          }
          .sticky-sidebar {
            position: static;
          }
          .search-box-container {
            max-width: 100% !important;
            width: 100%;
          }
        }
      `}} />
    </div>
  );
};

const NewsPage = () => (
  <ResolvedContentProvider>
    <NewsPageInner />
  </ResolvedContentProvider>
);

export default NewsPage;
